                  }}
                  onRemoved={async () => {
                    await sellerApi.updateSubscriptionPlan(token!, storeId, primaryPlan!.id, { image_url: "" });
                    showToast({ kind: "success", message: "Photo removed." });
                    await refreshAll(token!);
                  }}
