261вҶ’              aria-activedescendant={
262вҶ’                activeIndex >= 0 ? `prediction-${activeIndex}` : undefined
263вҶ’              }
264вҶ’              className="rounded-lg border border-[color:var(--lr-border)] bg-[color:var(--lr-bg)] px-3 py-2 text-sm text-[color:var(--lr-ink)] placeholder:text-[color:var(--lr-muted)] focus:outline-none focus:ring-2 focus:ring-[color:var(--lr-accent)]"
265вҶ’            />
