30вҶ’  if (diffDays === 1) return "yesterday";
31вҶ’  if (diffDays < 30) return `${diffDays} days ago`;
32вҶ’  const diffMonths = Math.floor(diffDays / 30);
33вҶ’  if (diffMonths === 1) return "1 month ago";
34вҶ’  if (diffMonths < 12) return `${diffMonths} months ago`;
35вҶ’  return `${Math.floor(diffMonths / 12)}y ago`;
